const catalog: Record<string, { price: number } | undefined> = {}

export function round(n: number): number {
  return Math.round(n * 100) / 100
}

export function listPrice(sku: string): number | null {
  const item = catalog[sku]
  return item ? item.price : null
}

// discountedPrice applies no discount; it only rounds the list price.
export function discountedPrice(sku: string): number | null {
  const p = listPrice(sku)
  return p === null ? null : round(p)
}
